/**
 * Script to generate placeholder test images for automation tests
 * Run this once: node tests/fixtures/generate-test-images.js
 */

const fs = require('fs');
const path = require('path');

// Create a minimal valid PNG (1x1 transparent pixel)
const minimalPNG = Buffer.from([
  0x89, 0x50, 0x4E, 0x47, 0x0D, 0x0A, 0x1A, 0x0A, // PNG signature
  0x00, 0x00, 0x00, 0x0D, // IHDR length
  0x49, 0x48, 0x44, 0x52, // IHDR
  0x00, 0x00, 0x00, 0x01, 0x00, 0x00, 0x00, 0x01, 0x08, 0x06, 0x00, 0x00, 0x00, // 1x1, 8-bit RGBA
  0x1F, 0x15, 0xC4, 0x89, // CRC
  0x00, 0x00, 0x00, 0x0A, // IDAT length
  0x49, 0x44, 0x41, 0x54, // IDAT
  0x78, 0x9C, 0x63, 0x00, 0x01, 0x00, 0x00, 0x05, 0x00, 0x01, // data
  0x0D, 0x0A, 0x2D, 0xB4, // CRC
  0x00, 0x00, 0x00, 0x00, // IEND length
  0x49, 0x45, 0x4E, 0x44, // IEND
  0xAE, 0x42, 0x60, 0x82  // CRC
]);

const fixturesDir = __dirname;
const imageNames = [
  'test-image-1.jpg',
  'test-image-2.jpg',
  'test-image-3.jpg',
  'test-image-4.jpg',
  'test-image-5.jpg'
];

// Generate images
imageNames.forEach((name) => {
  const filepath = path.join(fixturesDir, name);
  fs.writeFileSync(filepath, minimalPNG);
  console.log(`✓ Created ${name}`);
});

console.log(`\n✅ Generated ${imageNames.length} test images in ${fixturesDir}`);
